import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  Play, 
  Pause, 
  SkipForward, 
  SkipBack, 
  Volume2, 
  Moon, 
  Sun, 
  Baby, 
  Mic, 
  Video, 
  RefreshCw,
  Utensils, 
  Shirt, 
  Trees, 
  Gamepad2,
  BookOpen,
  Sparkles,
  Loader2,
  VolumeX
} from 'lucide-react';

// --- Types & Data ---

type Song = {
  id: string;
  title: string;
  category: 'Soothe' | 'Play';
  bpm: number;
  description: string;
  scienceNote: string;
  melody: number[]; 
  rhythm: number[]; 
};

// Frequencies
const NOTES = {
  C4: 261.63, D4: 293.66, E4: 329.63, F4: 349.23, G4: 392.00, A4: 440.00, B4: 493.88,
  C5: 523.25, D5: 587.33, E5: 659.25, G3: 196.00
};

const TRACK_LIST: Song[] = [
  {
    id: '1',
    title: "Brahms' Lullaby",
    category: 'Soothe',
    bpm: 60,
    description: "Traditional Piano & Hum",
    scienceNote: "Matches infant resting heart rate (60 BPM). Promotes entrainment.",
    melody: [NOTES.E4, NOTES.E4, NOTES.G4, NOTES.E4, NOTES.E4, NOTES.G4, NOTES.E4, NOTES.G4, NOTES.C5, NOTES.B4, NOTES.A4, NOTES.A4, NOTES.G4],
    rhythm: [0.5, 0.5, 1, 0.5, 0.5, 1, 0.5, 0.5, 1, 0.5, 0.5, 0.5, 2]
  },
  {
    id: '2',
    title: "Twinkle Twinkle (Slow)",
    category: 'Soothe',
    bpm: 65,
    description: "Simple Melody",
    scienceNote: "High predictability reduces cognitive load, lowering cortisol.",
    melody: [NOTES.C4, NOTES.C4, NOTES.G4, NOTES.G4, NOTES.A4, NOTES.A4, NOTES.G4, 0, NOTES.F4, NOTES.F4, NOTES.E4, NOTES.E4, NOTES.D4, NOTES.D4, NOTES.C4],
    rhythm: [0.5, 0.5, 0.5, 0.5, 0.5, 0.5, 1, 0.5, 0.5, 0.5, 0.5, 0.5, 0.5, 0.5, 1]
  },
  {
    id: '3',
    title: "Descending Scales",
    category: 'Soothe',
    bpm: 55,
    description: "Vocal Humming",
    scienceNote: "Descending melodic contours are universally recognized as 'soothing'.",
    melody: [NOTES.C5, NOTES.B4, NOTES.A4, NOTES.G4, NOTES.F4, NOTES.E4, NOTES.D4, NOTES.C4],
    rhythm: [0.8, 0.8, 0.8, 0.8, 0.8, 0.8, 0.8, 2]
  },
  {
    id: '4',
    title: "Pop Goes the Weasel",
    category: 'Play',
    bpm: 110,
    description: "Upbeat Rhythmic",
    scienceNote: "Syncopation creates surprise (dopamine) for active engagement.",
    melody: [NOTES.C4, NOTES.C4, NOTES.D4, NOTES.D4, NOTES.E4, NOTES.G4, NOTES.E4, NOTES.C4],
    rhythm: [0.3, 0.15, 0.3, 0.15, 0.3, 0.3, 0.3, 0.3]
  },
  {
    id: '5',
    title: "Clapping Song",
    category: 'Play',
    bpm: 120,
    description: "High Pitch & Fast",
    scienceNote: "Higher pitch registers engage the motor cortex for movement.",
    melody: [NOTES.G4, NOTES.G4, NOTES.E4, NOTES.G4, NOTES.G4, NOTES.E4, NOTES.G4, NOTES.A4, NOTES.G4, NOTES.E4, NOTES.C4],
    rhythm: [0.25, 0.25, 0.5, 0.25, 0.25, 0.5, 0.25, 0.25, 0.25, 0.25, 1]
  }
];

const SIGN_CARDS = [
  { id: 'eat', label: 'EAT', icon: Utensils, color: 'bg-orange-100 text-orange-600', signDesc: 'Hand to mouth' },
  { id: 'change', label: 'CHANGE', icon: Shirt, color: 'bg-blue-100 text-blue-600', signDesc: 'Fists together twist' },
  { id: 'play', label: 'PLAY', icon: Gamepad2, color: 'bg-purple-100 text-purple-600', signDesc: 'Shake Y-hands' },
  { id: 'outside', label: 'OUTSIDE', icon: Trees, color: 'bg-green-100 text-green-600', signDesc: 'Pull hand from head' },
];

export default function BabyDevice() {
  const [activeTab, setActiveTab] = useState<'music' | 'monitor' | 'mimic' | 'story'>('music');
  const apiKey = ""; 

  // Music State
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSongIndex, setCurrentSongIndex] = useState(0);
  const [progress, setProgress] = useState(0);
  const [audioDebugStatus, setAudioDebugStatus] = useState("Audio: Inactive");

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextNoteTimeRef = useRef<number>(0);
  const noteIndexRef = useRef<number>(0);
  const schedulerTimerRef = useRef<number | null>(null);

  // Monitor State
  const [activeSignIndex, setActiveSignIndex] = useState(0);
  const [isAutoCycling, setIsAutoCycling] = useState(false);
  const [routineSuggestion, setRoutineSuggestion] = useState<string | null>(null);
  const [isGeneratingRoutine, setIsGeneratingRoutine] = useState(false);

  // Story State
  const [storyPrompt, setStoryPrompt] = useState("");
  const [generatedStory, setGeneratedStory] = useState("");
  const [isGeneratingStory, setIsGeneratingStory] = useState(false);

  // Mimic State
  const [isMicActive, setIsMicActive] = useState(false);
  const [isCamActive, setIsCamActive] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [audioStatus, setAudioStatus] = useState("Ready");
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const [isRecording, setIsRecording] = useState(false);

  // --- GEMINI API HELPERS ---

  const callGemini = async (prompt: string): Promise<string> => {
    try {
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            contents: [{ parts: [{ text: prompt }] }],
          }),
        }
      );

      if (!response.ok) {
        throw new Error(`API call failed: ${response.statusText}`);
      }

      const data = await response.json();
      const text = data.candidates?.[0]?.content?.parts?.[0]?.text;
      return text || "Sorry, I couldn't generate a response right now.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "Unable to connect to AI service. Please try again.";
    }
  };

  const handleGenerateRoutine = async () => {
    setIsGeneratingRoutine(true);
    setRoutineSuggestion(null);
    const activity = SIGN_CARDS[activeSignIndex].label;

    const prompt = `Create a short, simple 1-hour schedule block for an 8-month-old baby named Riley that starts with the activity: ${activity}. Format it as a simple bulleted list with times (e.g., 0:00 - ${activity}). Keep it concise and practical.`;

    const result = await callGemini(prompt);
    setRoutineSuggestion(result);
    setIsGeneratingRoutine(false);
  };

  const handleGenerateStory = async () => {
    if (!storyPrompt.trim()) return;
    setIsGeneratingStory(true);
    setGeneratedStory("");

    const prompt = `Write a very short, soothing bedtime story (max 100 words) for a baby named Riley. The story should be about: ${storyPrompt}. Use calming, repetitive language suitable for an infant.`;

    const result = await callGemini(prompt);
    setGeneratedStory(result);
    setIsGeneratingStory(false);
  };

  // --- AUDIO ENGINE (SYNTHESIZER) ---

  // Create context immediately but don't start
  const getAudioContext = () => {
    if (!audioContextRef.current) {
        // Handle iOS vendor prefix if necessary, though AudioContext is standard now
        const AudioCtor = window.AudioContext || (window as any).webkitAudioContext;
        audioContextRef.current = new AudioCtor();
    }
    return audioContextRef.current;
  };

  const playTone = (freq: number, duration: number, time: number) => {
    const ctx = getAudioContext();
    if (!ctx) return;

    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine'; 
    osc.frequency.value = freq;

    const attack = Math.min(0.05, duration * 0.1); 
    const release = Math.min(0.05, duration * 0.1);

    gain.gain.setValueAtTime(0, time);
    gain.gain.linearRampToValueAtTime(0.4, time + attack); 
    gain.gain.setValueAtTime(0.4, time + duration - release);
    gain.gain.linearRampToValueAtTime(0, time + duration); 

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start(time);
    osc.stop(time + duration + 0.1);
  };

  const scheduleNotes = useCallback(() => {
    const ctx = getAudioContext();
    if (!ctx) return;

    const currentSong = TRACK_LIST[currentSongIndex];
    if (!currentSong) return;

    const tempoMultiplier = 60 / currentSong.bpm; 

    // Look ahead 0.1s
    while (nextNoteTimeRef.current < ctx.currentTime + 0.1) {
      const pitch = currentSong.melody[noteIndexRef.current];
      const rhythmVal = currentSong.rhythm[noteIndexRef.current];

      const duration = rhythmVal * tempoMultiplier;

      if (pitch > 0) {
        playTone(pitch, duration, nextNoteTimeRef.current);
      }

      nextNoteTimeRef.current += duration;
      noteIndexRef.current = (noteIndexRef.current + 1) % currentSong.melody.length;
    }

    // Update progress bar
    setProgress((prev) => (prev >= 100 ? 0 : prev + 1));

    schedulerTimerRef.current = window.setTimeout(scheduleNotes, 25);
  }, [currentSongIndex]);

  const startMusic = async () => {
    const ctx = getAudioContext();

    // iOS requires resume() to be called within a user interaction
    if (ctx.state === 'suspended') {
      try {
        await ctx.resume();
        setAudioDebugStatus("Audio: Resumed");
      } catch (e) {
        console.error(e);
        setAudioDebugStatus("Audio: Resume Failed");
      }
    } else {
        setAudioDebugStatus("Audio: Active");
    }

    noteIndexRef.current = 0;
    nextNoteTimeRef.current = ctx.currentTime + 0.05;

    setIsPlaying(true);
    scheduleNotes();
  };

  const stopMusic = () => {
    if (schedulerTimerRef.current) clearTimeout(schedulerTimerRef.current);
    setIsPlaying(false);
    setProgress(0);
    setAudioDebugStatus("Audio: Stopped");
  };

  useEffect(() => {
    return () => {
      if (schedulerTimerRef.current) clearTimeout(schedulerTimerRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  // Handle Song Change
  useEffect(() => {
    if (isPlaying) {
      stopMusic();
      // On song change, we don't need user interaction to resume if already playing
      setTimeout(startMusic, 100);
    }
  }, [currentSongIndex]);

  // DIRECT CLICK HANDLER FOR IOS
  const handlePlayClick = () => {
    if (isPlaying) {
      stopMusic();
    } else {
      // Must call startMusic (which calls ctx.resume) DIRECTLY in this click handler
      startMusic(); 
    }
  };

  const skip = (direction: 'next' | 'prev') => {
    stopMusic();
    if (direction === 'next') {
      setCurrentSongIndex(prev => (prev + 1) % TRACK_LIST.length);
    } else {
      setCurrentSongIndex(prev => (prev - 1 + TRACK_LIST.length) % TRACK_LIST.length);
    }
  };

  const currentSong = TRACK_LIST[currentSongIndex];

  // --- Monitor Logic ---

  useEffect(() => {
    let interval: number;
    if (isAutoCycling && activeTab === 'monitor') {
      interval = window.setInterval(() => {
        setActiveSignIndex(prev => (prev + 1) % SIGN_CARDS.length);
      }, 3000); // 3 seconds per sign
    }
    return () => clearInterval(interval);
  }, [isAutoCycling, activeTab]);

  // --- Mimic Logic (Webcam & Audio Echo) ---

  const toggleCamera = async () => {
    if (isCamActive) {
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(track => track.stop());
        videoRef.current.srcObject = null;
      }
      setIsCamActive(false);
    } else {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: true });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
        setIsCamActive(true);
      } catch (err) {
        console.error("Camera access denied", err);
        alert("Could not access camera. Please allow permissions.");
      }
    }
  };

  const startMimicLoop = async () => {
    if (isRecording) return;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        const audioUrl = URL.createObjectURL(audioBlob);
        const audio = new Audio(audioUrl);
        setAudioStatus("Repeating...");

        audio.playbackRate = 1.2; 
        audio.play().catch(e => console.log("Autoplay blocked:", e));

        audio.onended = () => {
          setAudioStatus("Listening...");
          if (isMicActive) {
            setTimeout(() => {
               if (mediaRecorderRef.current?.state === "inactive" && isMicActive) {
                 mediaRecorderRef.current.start();
                 setAudioStatus("Listening...");
                 setIsRecording(true);
                 setTimeout(() => {
                    if (mediaRecorderRef.current?.state === "recording") {
                       mediaRecorderRef.current.stop();
                       setIsRecording(false);
                    }
                 }, 3000); 
               }
            }, 500);
          }
        };
      };

      setIsMicActive(true);
      setAudioStatus("Listening...");
      mediaRecorder.start();
      setIsRecording(true);

      setTimeout(() => {
        if (mediaRecorder.state === "recording") {
            mediaRecorder.stop();
            setIsRecording(false);
        }
      }, 3000);

    } catch (err) {
      console.error("Mic access denied", err);
      alert("Could not access microphone.");
    }
  };

  const stopMimicLoop = () => {
    setIsMicActive(false);
    setAudioStatus("Ready");
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === "recording") {
      mediaRecorderRef.current.stop();
    }
  };

  useEffect(() => {
    if (activeTab !== 'music') {
        stopMusic();
    }
  }, [activeTab]);

  return (
    <div className="min-h-screen bg-cyan-50 flex items-center justify-center p-4 font-sans text-slate-700">

      {/* Device Chassis - Cyan Blue with Pink Highlights */}
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl border-8 border-cyan-200 overflow-hidden relative flex flex-col h-[700px]">

        {/* Top Bar / Status */}
        <div className="bg-cyan-100 p-4 flex justify-between items-center shrink-0">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 bg-pink-500 rounded-full animate-pulse"></div>
            <span className="text-xs font-bold text-cyan-700 tracking-wider">BABY FACE SMILES</span>
          </div>
          <div className="text-xs text-pink-500 font-bold uppercase">Riley's Lullaby</div>
        </div>

        {/* Main Display Area */}
        <div className="flex-1 bg-slate-50 relative flex flex-col overflow-y-auto">

          {/* TAB: MUSIC PLAYER */}
          {activeTab === 'music' && (
            <div className="flex-1 flex flex-col items-center justify-center p-6 text-center space-y-6 relative">

              {/* iOS Warning */}
              <div className="absolute top-2 left-0 w-full px-6">
                <div className="bg-yellow-50 text-yellow-700 text-[10px] p-2 rounded-lg border border-yellow-200 flex items-center justify-center gap-2">
                    <VolumeX size={12} />
                    <span>iPad Users: Ensure <strong>Silent Mode (Bell)</strong> is OFF in Control Center.</span>
                </div>
              </div>

              <div className={`mt-4 w-32 h-32 rounded-full flex items-center justify-center shadow-lg transition-all duration-1000 ${isPlaying ? 'scale-110 shadow-pink-200' : 'scale-100'} ${currentSong.category === 'Soothe' ? 'bg-cyan-100 text-cyan-600' : 'bg-orange-100 text-orange-500'}`}>
                {currentSong.category === 'Soothe' ? <Moon size={48} /> : <Sun size={48} />}
              </div>

              <div className="space-y-2">
                <h2 className="text-2xl font-bold text-slate-800">{currentSong.title}</h2>
                <p className="text-sm text-slate-500 font-medium">{currentSong.description}</p>
                <div className="inline-block px-3 py-1 bg-white rounded-full border border-cyan-200 text-xs text-cyan-600">
                  {currentSong.bpm} BPM
                </div>
              </div>

              <div className="bg-cyan-50 p-3 rounded-lg border border-cyan-100 text-xs text-cyan-800 italic">
                "{currentSong.scienceNote}"
              </div>

              {/* Progress Simulation - Pink Highlight */}
              <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
                <div className="bg-pink-500 h-full transition-all duration-300" style={{ width: `${progress}%` }}></div>
              </div>

              {/* Debug Status */}
              <div className="text-[10px] text-slate-400 font-mono">
                System Status: {audioDebugStatus}
              </div>
            </div>
          )}

          {/* TAB: MONITOR (SIGNS + AI ROUTINE) */}
          {activeTab === 'monitor' && (
            <div className="flex-1 flex flex-col items-center justify-start p-6 bg-slate-50 space-y-4">
              <div className={`w-full max-w-[260px] aspect-square ${SIGN_CARDS[activeSignIndex].color} rounded-2xl flex flex-col items-center justify-center shadow-lg transition-all duration-500`}>
                 {React.createElement(SIGN_CARDS[activeSignIndex].icon, { size: 64 })}
                 <h2 className="text-3xl font-black mt-4">{SIGN_CARDS[activeSignIndex].label}</h2>
                 <p className="mt-2 text-xs opacity-75 font-medium uppercase tracking-widest">{SIGN_CARDS[activeSignIndex].signDesc}</p>
              </div>

              <div className="flex gap-2">
                {SIGN_CARDS.map((_, idx) => (
                  <button 
                    key={idx}
                    onClick={() => { setActiveSignIndex(idx); setRoutineSuggestion(null); }}
                    className={`w-2 h-2 rounded-full transition-colors ${idx === activeSignIndex ? 'bg-cyan-600' : 'bg-slate-300'}`}
                  />
                ))}
              </div>

              <div className="w-full flex gap-2">
                <button 
                  onClick={() => setIsAutoCycling(!isAutoCycling)}
                  className={`flex-1 py-2 rounded-lg text-xs font-bold transition-colors ${isAutoCycling ? 'bg-pink-100 text-pink-600' : 'bg-slate-200 text-slate-500'}`}
                >
                  {isAutoCycling ? 'AUTO: ON' : 'AUTO: OFF'}
                </button>
                <button 
                  onClick={handleGenerateRoutine}
                  disabled={isGeneratingRoutine}
                  className="flex-1 py-2 rounded-lg text-xs font-bold bg-gradient-to-r from-purple-500 to-pink-500 text-white flex items-center justify-center gap-1 hover:opacity-90 disabled:opacity-50"
                >
                   {isGeneratingRoutine ? <Loader2 size={14} className="animate-spin" /> : <Sparkles size={14} />}
                   AI ROUTINE
                </button>
              </div>

              {/* AI Suggestion Box */}
              {routineSuggestion && (
                 <div className="w-full bg-white p-4 rounded-xl shadow-sm border border-pink-100 text-left animate-in fade-in slide-in-from-bottom-4">
                    <h3 className="text-xs font-bold text-pink-500 mb-2 flex items-center gap-1">
                        <Sparkles size={12} /> SUGGESTED ROUTINE
                    </h3>
                    <div className="text-xs text-slate-600 whitespace-pre-line leading-relaxed">
                        {routineSuggestion}
                    </div>
                 </div>
              )}
            </div>
          )}

          {/* TAB: STORY (NEW AI FEATURE) */}
          {activeTab === 'story' && (
            <div className="flex-1 flex flex-col p-6 bg-slate-50 overflow-y-auto">
               <div className="text-center mb-6">
                 <h2 className="text-xl font-bold text-slate-800 flex items-center justify-center gap-2">
                    <BookOpen className="text-cyan-500" /> Bedtime Stories
                 </h2>
                 <p className="text-xs text-slate-500">Generate a soothing tale for Riley</p>
               </div>

               <div className="space-y-4">
                  <div className="bg-white p-4 rounded-xl shadow-sm border border-cyan-100">
                     <label className="text-xs font-bold text-cyan-700 block mb-2">STORY THEME</label>
                     <div className="flex gap-2">
                        <input 
                            type="text" 
                            value={storyPrompt}
                            onChange={(e) => setStoryPrompt(e.target.value)}
                            placeholder="e.g., A sleepy bunny, Clouds..."
                            className="flex-1 text-sm p-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:border-cyan-400"
                        />
                        <button 
                            onClick={handleGenerateStory}
                            disabled={isGeneratingStory || !storyPrompt.trim()}
                            className="bg-cyan-500 text-white p-2 rounded-lg disabled:opacity-50 hover:bg-cyan-600"
                        >
                            {isGeneratingStory ? <Loader2 size={18} className="animate-spin" /> : <Sparkles size={18} />}
                        </button>
                     </div>
                  </div>

                  {generatedStory ? (
                      <div className="bg-white p-6 rounded-xl shadow-sm border border-pink-100 relative">
                          <div className="absolute -top-3 left-4 bg-pink-100 text-pink-600 text-[10px] font-bold px-2 py-1 rounded-full">
                              AI GENERATED
                          </div>
                          <p className="text-sm leading-7 text-slate-700 font-medium font-serif">
                              {generatedStory}
                          </p>
                      </div>
                  ) : (
                      <div className="text-center py-10 opacity-40">
                          <BookOpen size={48} className="mx-auto mb-2 text-slate-300" />
                          <p className="text-xs">Enter a theme to begin reading</p>
                      </div>
                  )}
               </div>
            </div>
          )}

          {/* TAB: MIMIC (MIRROR) */}
          {activeTab === 'mimic' && (
            <div className="flex-1 relative bg-black flex flex-col items-center justify-center overflow-hidden">
              {/* Camera Feed */}
              <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline
                className={`absolute inset-0 w-full h-full object-cover transition-opacity ${isCamActive ? 'opacity-100' : 'opacity-0'}`} 
              />

              {!isCamActive && (
                <div className="text-white text-center p-6 opacity-50 z-10">
                  <Baby size={64} className="mx-auto mb-4 text-pink-300" />
                  <p>Tap camera button to activate Mirror Mode</p>
                </div>
              )}

              {/* Audio Visualizer Overlay */}
              {isMicActive && (
                <div className="absolute bottom-20 left-1/2 -translate-x-1/2 bg-black/60 px-6 py-2 rounded-full backdrop-blur-sm z-20">
                  <div className="flex items-center gap-3">
                    <div className={`w-3 h-3 rounded-full ${audioStatus === 'Listening...' ? 'bg-pink-500 animate-pulse' : 'bg-green-500'}`}></div>
                    <span className="text-white font-mono text-sm">{audioStatus}</span>
                    {audioStatus === 'Repeating...' && (
                        <div className="flex gap-1 h-3 items-end">
                            <div className="w-1 bg-white animate-bounce" style={{animationDelay: '0ms'}}></div>
                            <div className="w-1 bg-white animate-bounce" style={{animationDelay: '100ms'}}></div>
                            <div className="w-1 bg-white animate-bounce" style={{animationDelay: '200ms'}}></div>
                        </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {/* Controls / Navigation */}
        <div className="bg-white p-4 border-t border-cyan-100 shrink-0">

          {/* Controls for Music Tab */}
          {activeTab === 'music' && (
            <div className="flex justify-center mb-6">
              <div className="flex items-center gap-6">
                <button onClick={() => skip('prev')} className="text-cyan-300 hover:text-cyan-500"><SkipBack size={24} /></button>
                <button 
                  onClick={handlePlayClick} 
                  className="w-16 h-16 bg-pink-500 rounded-full text-white flex items-center justify-center shadow-lg shadow-pink-200 active:scale-95 transition-transform"
                >
